proof fn phi_1_stable_target_any_execution(p: TempPred<int>, a_to_q: spec_fn(int) -> TempPred<int>, ex: Execution<int>)
    requires
        forall |a: int| #[trigger] valid(stable(p.leads_to(a_to_q(a)))),
    ensures
        stable(tla_forall(|a: int| p.leads_to(a_to_q(a)))).satisfied_by(ex),
{
    tla_forall_a_p_leads_to_q_a_is_stable::<int, int>(p, a_to_q);
}

proof fn phi_2_leads_to_preserved_at_suffix(p: TempPred<int>, q: TempPred<int>, ex: Execution<int>, i: nat)
    requires
        valid(stable(p.leads_to(q))),
        p.leads_to(q).satisfied_by(ex),
    ensures
        p.leads_to(q).satisfied_by(ex.suffix(i)),
{
    tla_forall_a_p_leads_to_q_a_is_stable::<int, int>(p, |_a: int| q);
}

proof fn phi_3_always_leads_to_from_stable(p: TempPred<int>, q: TempPred<int>, ex: Execution<int>)
    requires
        valid(stable(p.leads_to(q))),
        p.leads_to(q).satisfied_by(ex),
    ensures
        always(p.leads_to(q)).satisfied_by(ex),
{
    assert(stable(p.leads_to(q)).satisfied_by(ex));
}

proof fn phi_4_tla_forall_leads_to_from_components(p: TempPred<int>, a_to_q: spec_fn(int) -> TempPred<int>, ex: Execution<int>)
    requires
        forall |a: int| #[trigger] valid(stable(p.leads_to(a_to_q(a)))),
        forall |a: int| #[trigger] p.leads_to(a_to_q(a)).satisfied_by(ex),
    ensures
        always(tla_forall(|a: int| p.leads_to(a_to_q(a)))).satisfied_by(ex),
{
    tla_forall_a_p_leads_to_q_a_is_stable::<int, int>(p, a_to_q);
}
